/// <summary>
/// Extension of the <c>InventJournalCheckPost</c> class for the ETGSPAIN model.
/// </summary>
[ExtensionOf(classStr(InventJournalCheckPost))]
final class InventJournalCheckPostETGSPAIN_Extension
{    
}

Method.Source:
/// <summary>
/// Extension of the <c>newFromForm</c> method.
/// </summary>
/// <param name="_args">Arguments for the method.</param>
/// <param name="_journalForm">The journal form being processed.</param>
/// <returns>Returns a new instance of <c>JournalCheckPost</c>.</returns>
protected static JournalCheckPost newFromForm(
    Args            _args,
    JournalForm     _journalForm)
{        
    InventJournalTable  inventJournalTable  = _journalForm.journalTableData().journalTable();
    InventJournalTrans  inventJournalTrans;

    if (InventJournalName::find(inventJournalTable.JournalNameId).JournalType == InventJournalType::Transfer)
    {
        /*
        // Comprobamos si existe alguna línea con "Cantidad Aplicada" igual a Cero.
        select firstonly inventJournalTrans
            where        inventJournalTrans.JournalId           == inventJournalTable.JournalId
            &&           inventJournalTrans.ETGSPAINInventAppliedQty == 0;

        // En el caso de que exista, mostramos mensaje para que el usuario confirme si desea continuar con el proceso de registro.
        if (inventJournalTrans)
        {
            if (!Box::confirm("@ETGSPAINLabels:QuestionExistAppliedQtyWithZero"))
            {                    
                throw error("@ETGSPAINLabels:PostCanceled");
            }
        }   
        */
    }

    return next newFromForm(_args, _journalForm);        
}
